import{_ as s,o as a,c as i,aw as e}from"./chunks/framework.Dq2onT5h.js";const n=JSON.parse('{"title":"Aggregator Node","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"Aggregator Node | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"guides/running-nodes/aggregator.md","filePath":"guides/running-nodes/aggregator.md","lastUpdated":1772446570000}');const t=s({name:"guides/running-nodes/aggregator.md"},[["render",function(s,n,t,l,h,o){return a(),i("div",null,[...n[0]||(n[0]=[e('<h1 id="aggregator-node" tabindex="-1">Aggregator Node <a class="header-anchor" href="#aggregator-node" aria-label="Permalink to &quot;Aggregator Node&quot;">​</a></h1><p>An aggregator (also called sequencer) is the node responsible for producing blocks in an Evolve chain. It collects transactions, orders them, creates blocks, and submits data to the DA layer.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>ev-node installed</li><li>Access to a DA layer (Celestia or local-da)</li><li>Signer key for block signing</li></ul><h2 id="configuration" tabindex="-1">Configuration <a class="header-anchor" href="#configuration" aria-label="Permalink to &quot;Configuration&quot;">​</a></h2><p>Enable aggregator mode with the <code>--evnode.node.aggregator</code> flag:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --evnode.node.aggregator</span></span></code></pre></div><h3 id="required-flags" tabindex="-1">Required Flags <a class="header-anchor" href="#required-flags" aria-label="Permalink to &quot;Required Flags&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.node.aggregator</code></td><td>Enable block production</td></tr><tr><td><code>--evnode.da.address</code></td><td>DA layer endpoint</td></tr><tr><td><code>--evnode.signer.passphrase</code></td><td>Signer key passphrase</td></tr></tbody></table><h3 id="block-time-configuration" tabindex="-1">Block Time Configuration <a class="header-anchor" href="#block-time-configuration" aria-label="Permalink to &quot;Block Time Configuration&quot;">​</a></h3><p>Control how often blocks are produced:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Produce blocks every 500ms</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.block_time</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 500ms</span></span></code></pre></div><p>Default block time is 1 second.</p><h2 id="lazy-aggregation-mode" tabindex="-1">Lazy Aggregation Mode <a class="header-anchor" href="#lazy-aggregation-mode" aria-label="Permalink to &quot;Lazy Aggregation Mode&quot;">​</a></h2><p>Lazy mode only produces blocks when there are transactions, reducing DA costs during low activity periods:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.lazy_aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.lazy_block_time</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 30s</span></span></code></pre></div><table tabindex="0"><thead><tr><th>Flag</th><th>Description</th></tr></thead><tbody><tr><td><code>--evnode.node.lazy_aggregator</code></td><td>Enable lazy mode</td></tr><tr><td><code>--evnode.node.lazy_block_time</code></td><td>Max wait between blocks in lazy mode</td></tr></tbody></table><p>In lazy mode:</p><ul><li>Blocks are produced immediately when transactions arrive</li><li>If no transactions, wait up to <code>lazy_block_time</code> before producing an empty block</li><li>Reduces DA submission costs during idle periods</li></ul><h2 id="da-submission-settings" tabindex="-1">DA Submission Settings <a class="header-anchor" href="#da-submission-settings" aria-label="Permalink to &quot;DA Submission Settings&quot;">​</a></h2><p>Configure how blocks are batched and submitted to DA:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.address</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:26658</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;my_namespace&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.gas_price</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.01</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.batching_strategy</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> adaptive</span></span></code></pre></div><h3 id="batching-strategies" tabindex="-1">Batching Strategies <a class="header-anchor" href="#batching-strategies" aria-label="Permalink to &quot;Batching Strategies&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Strategy</th><th>Description</th></tr></thead><tbody><tr><td><code>immediate</code></td><td>Submit as soon as blocks are ready</td></tr><tr><td><code>time</code></td><td>Wait for time interval before submitting</td></tr><tr><td><code>size</code></td><td>Wait until batch reaches size threshold</td></tr><tr><td><code>adaptive</code></td><td>Balance between size and time (recommended)</td></tr></tbody></table><h3 id="max-pending-blocks" tabindex="-1">Max Pending Blocks <a class="header-anchor" href="#max-pending-blocks" aria-label="Permalink to &quot;Max Pending Blocks&quot;">​</a></h3><p>Limit how many blocks can be waiting for DA submission:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--evnode.node.max_pending_blocks</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 100</span></span></code></pre></div><p>When this limit is reached, block production pauses until some blocks are confirmed on DA.</p><h2 id="signer-configuration" tabindex="-1">Signer Configuration <a class="header-anchor" href="#signer-configuration" aria-label="Permalink to &quot;Signer Configuration&quot;">​</a></h2><p>The aggregator needs a signer key to sign blocks:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Using file-based signer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.signer.signer_type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.signer.signer_path</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path/to/keys</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.signer.passphrase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;your-passphrase&quot;</span></span></code></pre></div><h2 id="complete-example" tabindex="-1">Complete Example <a class="header-anchor" href="#complete-example" aria-label="Permalink to &quot;Complete Example&quot;">​</a></h2><h3 id="evm-chain-ev-reth" tabindex="-1">EVM Chain (ev-reth) <a class="header-anchor" href="#evm-chain-ev-reth" aria-label="Permalink to &quot;EVM Chain (ev-reth)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.block_time</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.address</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:26658</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;my_evm_chain&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.gas_price</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 0.01</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.signer.passphrase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;secret&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.rpc.address</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> tcp://0.0.0.0:26657</span></span></code></pre></div><h3 id="cosmos-sdk-chain-ev-abci" tabindex="-1">Cosmos SDK Chain (ev-abci) <a class="header-anchor" href="#cosmos-sdk-chain-ev-abci" aria-label="Permalink to &quot;Cosmos SDK Chain (ev-abci)&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">appd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.block_time</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> 1s</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.address</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:26658</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.da.namespace</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;my_cosmos_chain&quot;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.signer.passphrase</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;secret&quot;</span></span></code></pre></div><h2 id="monitoring" tabindex="-1">Monitoring <a class="header-anchor" href="#monitoring" aria-label="Permalink to &quot;Monitoring&quot;">​</a></h2><p>Enable metrics to monitor aggregator performance:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">evnode</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> start</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.node.aggregator</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.instrumentation.prometheus</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --evnode.instrumentation.prometheus_listen_addr</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> :2112</span></span></code></pre></div><p>Key metrics to watch:</p><ul><li><code>evolve_block_height</code> - Current block height</li><li><code>evolve_da_submission_total</code> - DA submissions count</li><li><code>evolve_da_submission_failures</code> - Failed DA submissions</li></ul><p>Enable the DA visualizer for detailed submission monitoring:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">--evnode.rpc.enable_da_visualization</span></span></code></pre></div><p>Then access <code>http://localhost:7331/da</code> in your browser.</p><h2 id="health-checks" tabindex="-1">Health Checks <a class="header-anchor" href="#health-checks" aria-label="Permalink to &quot;Health Checks&quot;">​</a></h2><p>The aggregator exposes health endpoints:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Liveness check</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:7331/health/live</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Readiness check (includes block production rate)</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://localhost:7331/health/ready</span></span></code></pre></div><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><h3 id="blocks-not-being-produced" tabindex="-1">Blocks Not Being Produced <a class="header-anchor" href="#blocks-not-being-produced" aria-label="Permalink to &quot;Blocks Not Being Produced&quot;">​</a></h3><ol><li>Verify aggregator mode is enabled in logs</li><li>Check DA layer connectivity</li><li>Ensure signer key is accessible</li></ol><h3 id="da-submission-failures" tabindex="-1">DA Submission Failures <a class="header-anchor" href="#da-submission-failures" aria-label="Permalink to &quot;DA Submission Failures&quot;">​</a></h3><ol><li>Check DA layer endpoint is reachable</li><li>Verify DA account has sufficient funds</li><li>Increase gas price if transactions are being outbid</li></ol><h3 id="high-pending-block-count" tabindex="-1">High Pending Block Count <a class="header-anchor" href="#high-pending-block-count" aria-label="Permalink to &quot;High Pending Block Count&quot;">​</a></h3><ol><li>Reduce block time or enable lazy mode</li><li>Increase DA gas price for faster inclusion</li><li>Check DA layer congestion</li></ol><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/guides/running-nodes/full-node">Full Node Guide</a> - Running a non-producing node</li><li><a href="/guides/tools/visualizer">DA Visualization</a> - Monitor DA submissions</li><li><a href="/guides/operations/monitoring">Monitoring Guide</a> - Prometheus metrics</li></ul>',56)])])}]]);export{n as __pageData,t as default};
